#include <random>
#include <vector>
#include <cmath>

class Solution {
public:
    Solution(double radius, double x_center, double y_center) {
        // Initialize random number generator
        std::default_random_engine generator;
        std::uniform_real_distribution<double> distribution(0.0, 1.0 - radius);

        // Calculate the distance from the center to the origin
        double distance = sqrt(pow(radius, 2) + pow(x_center - radius, 2) + pow(y_center - radius, 2));

        // Calculate the angle in radians
        double angle = acos((x_center - radius) / distance);

        // Calculate the x and y coordinates of the random point
        double x = radius * cos(angle);
        double y = radius * sin(angle);
    }

    vector<double> randPoint() {
        // Generate random x and y coordinates
        double x, y;
        std::generate_n(std::begin(x), 2, [&]() { return distribution(generator); });
        std::generate_n(std::begin(y), 2, [&]() { return distribution(generator); });

        // Check if the generated coordinates are within the circle
        if (x * x + y * y <= radius * radius) {
            return {x, y};
        } else {
            // Generate new coordinates if the point is outside the circle
            x = radius * cos(angle);
            y = radius * sin(angle);
            return {x, y};
        }
    }
};
